  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('835395b1-864d-508c-b18a-c2d4e5a03fb3', 'eveil-scientifique-2eme', 'التغذية', 'الأكل المتنوّع والصحّي، وجبات اليوم، الأطعمة المفيدة (الخضر والغلال والحليب) مقابل الإكثار من الحلويات، وأهمّية شرب الماء', '# ⚔️ التغذية — وقودُ جسمنا

> 💡 «الطعام الصحّي يعطيني قوّةً لأنمو وألعب وأتعلّم.»

نأكل لنحصل على **الطاقة** والقوّة، ولكي ينمو جسمنا. لكنّ ليس كلّ طعامٍ مفيدًا بنفس القدر؛ المهمّ أن نأكل **طعامًا متنوّعًا وصحّيًّا**.

## 🍽️ لماذا نأكل؟

نأكل لأنّ الطعام يعطي جسمنا الطاقة ليتحرّك ويلعب، ويساعده على **النموّ** وعلى البقاء في صحّة جيّدة.

## 🥗 الطعام المتنوّع

لكي نكون أصحّاء نأكل من أنواعٍ مختلفة:

- **الخضر والغلال** (الفواكه والخضروات) فيها فيتامينات تحمينا من المرض.
- **الحليب ومشتقّاته** تقوّي العظام والأسنان.
- **الخبز والأرزّ** يعطيان طاقة.
- **اللحم والسمك والبيض** تساعد الجسم على النموّ.

## ⏰ وجبات اليوم

نأكل في أوقاتٍ منتظمة. أهمّ الوجبات: **الفطور** في الصباح (لا نخرج إلى المدرسة دون فطور)، ثمّ **الغداء**، ثمّ **العشاء**.

## 🍬 الأطعمة المفيدة والأطعمة التي نقلّل منها

- **مفيدة:** الخضر، الغلال، الحليب، الماء.
- **نقلّل منها:** الحلويات والمشروبات السكّرية والأكلات الدهنية كثيرًا؛ فالإكثار منها يضرّ الأسنان والجسم.

## 💧 شرب الماء

الماء مهمّ جدًّا لجسمنا، لذلك **نشرب ماءً نظيفًا** كلّ يوم، خاصّةً عند الشعور بالعطش وبعد اللعب.

> ⚠️ الفخّ الشائع: الظنّ أنّ الحلويات «طعامٌ جيّد لأنّها لذيذة». اللذّة شيءٌ والفائدة شيءٌ آخر؛ الأفضل أن نُكثر من الخضر والغلال ونقلّل من الحلويات.

> 🏆 ممتاز! صرت تعرف كيف تختار طعامًا متنوّعًا وصحّيًّا ليبقى جسمك قويًّا.', '# 📜 ملخّص: التغذية

- **نأكل** لنحصل على الطاقة والقوّة ولينمو جسمنا.
- **الطعام المتنوّع:** الخضر والغلال (فيتامينات)، الحليب (عظام وأسنان)، الخبز والأرزّ (طاقة)، اللحم والسمك والبيض (نموّ).
- **وجبات اليوم:** الفطور ثمّ الغداء ثمّ العشاء؛ لا نخرج إلى المدرسة دون فطور.
- **مفيدة:** الخضر، الغلال، الحليب، الماء.
- **نقلّل منها:** الحلويات والمشروبات السكّرية والأكلات الدهنية.
- **الماء** مهمّ جدًّا، نشرب ماءً نظيفًا كلّ يوم.
- **القاعدة:** الطعام اللذيذ ليس دائمًا مفيدًا؛ نُكثر من الخضر والغلال.', 3)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('d758f08c-26a6-540f-a1d9-82a64776dde5', 'eveil-scientifique-2eme', 'الحيوانات', 'أوساط عيش الحيوانات، تغذية الحيوانات (عاشبة ولاحمة)، طرق التنقّل (المشي والطيران والسباحة والزحف)، والتكاثر (بيض أو ولادة صغار)', '# ⚔️ الحيوانات — أصدقاؤنا في الطبيعة

> 💡 «حولنا حيواناتٌ كثيرة: منها من يمشي ومنها من يطير، ولكلٍّ طريقته في العيش.»

الحيوانات كائناتٌ حيّة تأكل وتتحرّك وتتكاثر. وهي تختلف في أماكن عيشها وطعامها وطريقة تنقّلها وتكاثرها. لنكتشفها معًا.

## 🏞️ أين تعيش الحيوانات؟

تعيش الحيوانات في أوساطٍ مختلفة:

- **في البرّ (اليابسة):** مثل القطّ والأسد والحصان.
- **في الماء:** مثل السمك والحوت.
- **في الهواء (تطير):** مثل العصفور والنحلة.

## 🍖 ماذا تأكل الحيوانات؟

حسب طعامها نقسم الحيوانات إلى:

- **حيوانات عاشبة:** تأكل **النبات** (العشب، الأوراق)، مثل الخروف والأرنب والبقرة.
- **حيوانات لاحمة:** تأكل **اللحم** (حيواناتٍ أخرى)، مثل الأسد والقطّ والذئب.

## 🐾 كيف تتنقّل الحيوانات؟

تتنقّل الحيوانات بطرقٍ مختلفة:

- **المشي والجري:** بالأرجل، مثل الحصان والكلب.
- **الطيران:** بالأجنحة، مثل العصفور.
- **السباحة:** في الماء، مثل السمك.
- **الزحف:** على البطن، مثل الأفعى.

## 🥚 كيف تتكاثر الحيوانات؟

تأتي صغار الحيوانات بطريقتين:

- بعض الحيوانات **تبيض** ثمّ يخرج الصغير من البيضة، مثل الدجاجة والعصفور والسمك.
- وبعضها **تلد** صغارًا حيّة، مثل القطّة والبقرة والكلبة.

> ⚠️ الفخّ الشائع: الظنّ أنّ كلّ الحيوانات تأكل نفس الطعام. الصحيح أنّ العاشبة تأكل النبات واللاحمة تأكل اللحم.

> 🏆 رائع! صرت تعرف أين تعيش الحيوانات وماذا تأكل وكيف تتنقّل وتتكاثر.', '# 📜 ملخّص: الحيوانات

- **أوساط العيش:** في البرّ (القطّ، الأسد)، في الماء (السمك، الحوت)، في الهواء (العصفور).
- **التغذية:** حيوانات **عاشبة** تأكل النبات (الخروف، الأرنب)، وحيوانات **لاحمة** تأكل اللحم (الأسد، القطّ).
- **التنقّل:** المشي والجري (الحصان)، الطيران (العصفور)، السباحة (السمك)، الزحف (الأفعى).
- **التكاثر:** بعضها **يبيض** (الدجاجة، العصفور، السمك)، وبعضها **يلد** صغارًا حيّة (القطّة، البقرة).
- **القاعدة:** الحيوانات تختلف في الطعام؛ العاشبة للنبات واللاحمة للّحم.', 4)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('1c559e0d-2a3c-5446-b0f7-8aa4b78d09a0', 'eveil-scientifique-2eme', 'النباتات', 'أجزاء النبات (الجذر والساق والأوراق والزهرة)، حاجات النبات للنموّ (الماء والضوء والهواء)، ونموّ البذرة لتصير نباتًا', '# ⚔️ النباتات — كائناتٌ حيّة تنمو

> 💡 «النبات كائنٌ حيّ: يشرب الماء ويحبّ الضوء وينمو كما ننمو نحن.»

النباتات من حولنا كثيرة: الأشجار والأزهار والخضر. وهي **كائناتٌ حيّة** تنمو وتكبر. لنتعرّف على أجزائها وحاجاتها وكيف تنمو.

## 🌿 أجزاء النبات

للنبات أجزاءٌ أساسية:

- **الجذر:** في باطن الأرض، يثبّت النبات ويمتصّ الماء.
- **الساق:** يحمل النبات ويرفعه إلى الأعلى.
- **الأوراق:** خضراء، يصنع بها النبات غذاءه بمساعدة الضوء.
- **الزهرة:** الجزء الملوّن، ومنها يتكوّن الثمر والبذور.

## 💧 ماذا يحتاج النبات لينمو؟

لكي ينمو النبات ويبقى حيًّا يحتاج إلى:

- **الماء** (نسقيه).
- **الضوء** (ضوء الشمس).
- **الهواء**.

إن نقص أحد هذه الأشياء يذبل النبات وقد يموت.

## 🌱 كيف تنمو البذرة؟

نضع **البذرة** في التربة ونسقيها بالماء. بعد أيّامٍ تنبت: يخرج منها جذرٌ صغير إلى أسفل وساقٌ صغير إلى أعلى، ثمّ تظهر **الأوراق**، ويكبر النبات شيئًا فشيئًا حتّى يصير نباتًا كاملًا.

> ⚠️ الفخّ الشائع: الظنّ أنّ النبات يحتاج إلى الماء فقط. الصحيح أنّه يحتاج إلى **الماء والضوء والهواء** معًا لينمو جيّدًا.

> 🏆 ممتاز! صرت تعرف أجزاء النبات وما يحتاجه لينمو وكيف تنبت البذرة.', '# 📜 ملخّص: النباتات

- **النبات كائنٌ حيّ** ينمو ويكبر.
- **أجزاء النبات:** الجذر (يثبّت ويمتصّ الماء)، الساق (يحمل النبات)، الأوراق (تصنع الغذاء بالضوء)، الزهرة (منها الثمر والبذور).
- **حاجات النبات لينمو:** الماء، الضوء، الهواء.
- **نموّ البذرة:** نضعها في التربة ونسقيها، فتنبت بجذرٍ إلى أسفل وساقٍ إلى أعلى، ثمّ أوراق، ثمّ تكبر.
- **القاعدة:** النبات يحتاج إلى الماء والضوء والهواء معًا، وليس الماء وحده.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('ae6170c9-2ef1-5e15-9885-7258249af068', 'eveil-scientifique-2eme', 'الماء في الطبيعة', 'أين نجد الماء في الطبيعة (البحر والنهر والمطر والعين)، استعمالات الماء في حياتنا، حالاته الظاهرة البسيطة (سائل وجامد)، وأهمّية المحافظة على الماء وعدم تبذيره', '# ⚔️ الماء في الطبيعة — كنزُ الحياة

> 💡 «الماء أصل الحياة: نشربه ونغتسل به، وبه تعيش النباتات والحيوانات.»

الماء موجودٌ في كلّ مكانٍ حولنا، وهو مهمّ جدًّا لكلّ الكائنات الحيّة. لنتعرّف على أين نجده وكيف نستعمله وكيف نحافظ عليه.

## 🌊 أين نجد الماء في الطبيعة؟

نجد الماء في أماكن كثيرة:

- في **البحر** وفي **النهر** وفي **العين** والبئر.
- يسقط من السماء على شكل **مطر**.

## 🚰 استعمالات الماء

نستعمل الماء كلّ يوم في أشياء كثيرة:

- **للشرب** (نحن والحيوانات).
- **لسقي النباتات والزرع**.
- **للنظافة:** الاستحمام، غسل اليدين، غسل الملابس والأواني.
- **للطبخ**.

## ❄️ حالات الماء البسيطة

نرى الماء في حالتين بسيطتين:

- **الماء السائل:** كماء البحر والمطر ومياه الصنبور.
- **الماء الجامد (الجليد):** عندما يصير الماء باردًا جدًّا يتجمّد ويصبح **جليدًا** صلبًا.

## 💧 نحافظ على الماء

الماء ثمين، لذلك لا نبذّره. من سلوكات المحافظة على الماء:

- نغلق الصنبور جيّدًا بعد الاستعمال.
- لا نترك الماء يجري دون فائدة.
- نُصلح الصنابير التي تُسرّب الماء.

> ⚠️ الفخّ الشائع: الظنّ أنّ الماء لا ينفد لأنّه كثير. الصحيح أنّ الماء الصالح للشرب ثمين ومحدود، لذلك نوفّره ولا نبذّره.

> 🏆 رائع! صرت تعرف أين نجد الماء وكيف نستعمله وكيف نحافظ عليه.', '# 📜 ملخّص: الماء في الطبيعة

- **أين نجد الماء:** في البحر والنهر والعين والبئر، ويسقط من السماء على شكل مطر.
- **استعمالاته:** الشرب، سقي النباتات، النظافة (الاستحمام وغسل اليدين والملابس)، الطبخ.
- **حالاته البسيطة:** ماء **سائل** (البحر، المطر، الصنبور)، وماء **جامد** (الجليد) عندما يبرد جدًّا.
- **نحافظ على الماء:** نغلق الصنبور، ولا نترك الماء يجري، ونُصلح ما يُسرّب الماء.
- **القاعدة:** الماء الصالح للشرب ثمين ومحدود، فنوفّره ولا نبذّره.', 6)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('61e5e59d-d51d-50c3-bf4b-75d51700a1d1', 'eveil-scientifique-2eme', 'الفصول الأربعة', 'الفصول الأربعة (الربيع والصيف والخريف والشتاء)، طقس كلّ فصل، الملابس المناسبة له، وتغيّرات الطبيعة في كلّ فصل', '# ⚔️ الفصول الأربعة — رحلةُ السنة

> 💡 «تمرّ السنة بأربعة فصول: ربيعٌ وصيفٌ وخريفٌ وشتاء، ولكلٍّ طقسه وجماله.»

تنقسم السنة إلى **أربعة فصول**، يأتي كلّ واحدٍ بعد الآخر. في كلّ فصلٍ يتغيّر الطقس وتتغيّر الطبيعة وملابسنا. لنتعرّف عليها.

## 🌸 الربيع

في **الربيع** يصير الجوّ معتدلًا (لا حارًّا ولا باردًا)، **تتفتّح الأزهار** وتخضرّ الأشجار، وتعود الطيور. نلبس ملابس خفيفة معتدلة.

## ☀️ الصيف

في **الصيف** يصير الجوّ **حارًّا** ومشمسًا، ويطول النهار. نلبس ملابس **خفيفة** ونشرب ماءً كثيرًا ونحتمي من الشمس.

## 🍂 الخريف

في **الخريف** يبرد الجوّ شيئًا فشيئًا، **تتساقط أوراق الأشجار** الصفراء، ويبدأ المطر. نلبس ملابس متوسّطة.

## ❄️ الشتاء

في **الشتاء** يصير الجوّ **باردًا**، ويكثر **المطر** وأحيانًا الثلج، ويقصر النهار. نلبس ملابس **ثقيلة** ودافئة (معطف، قبّعة).

## 🌗 ترتيب الفصول

تأتي الفصول بترتيبٍ ثابت يتكرّر كلّ سنة: **الربيع ← الصيف ← الخريف ← الشتاء**، ثمّ يعود الربيع من جديد.

> ⚠️ الفخّ الشائع: الخلط بين ملابس الفصول؛ في الصيف الحارّ نلبس الخفيف، وفي الشتاء البارد نلبس الثقيل الدافئ.

> 🏆 ممتاز! صرت تعرف الفصول الأربعة وطقس كلّ فصلٍ وملابسه وتغيّرات الطبيعة فيه.', '# 📜 ملخّص: الفصول الأربعة

- **السنة أربعة فصول:** الربيع، الصيف، الخريف، الشتاء.
- **الربيع:** جوّ معتدل، تتفتّح الأزهار وتخضرّ الأشجار؛ ملابس خفيفة معتدلة.
- **الصيف:** جوّ حارّ مشمس والنهار طويل؛ ملابس خفيفة ونشرب ماءً كثيرًا.
- **الخريف:** يبرد الجوّ وتتساقط أوراق الأشجار ويبدأ المطر؛ ملابس متوسّطة.
- **الشتاء:** جوّ بارد، مطر وثلج والنهار قصير؛ ملابس ثقيلة دافئة (معطف، قبّعة).
- **الترتيب:** الربيع ← الصيف ← الخريف ← الشتاء، ثمّ يتكرّر.
- **القاعدة:** نلبس حسب الفصل؛ الخفيف في الصيف والثقيل الدافئ في الشتاء.', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
